import React, { useState } from 'react';
import axios from 'axios';
import './App.css';

function App() {
  const [selectedFile, setSelectedFile] = useState(null);
  const [preview, setPreview] = useState(null);
  const [predictions, setPredictions] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [apiUrl] = useState('http://localhost:8000');

  const handleFileSelect = (event) => {
    const file = event.target.files[0];
    if (file) {
      // Validate file type
      if (!file.type.startsWith('image/')) {
        setError('Please select a valid image file');
        return;
      }

      // Validate file size (max 50MB)
      if (file.size > 50 * 1024 * 1024) {
        setError('File size must be less than 50MB');
        return;
      }

      setSelectedFile(file);
      setError(null);

      // Create preview
      const reader = new FileReader();
      reader.onloadend = () => {
        setPreview(reader.result);
      };
      reader.readAsDataURL(file);
    }
  };

  const handlePredict = async () => {
    if (!selectedFile) {
      setError('Please select an image first');
      return;
    }

    setLoading(true);
    setError(null);
    setPredictions(null);

    try {
      const formData = new FormData();
      formData.append('file', selectedFile);

      const response = await axios.post(`${apiUrl}/predict`, formData, {
        headers: {
          'Content-Type': 'multipart/form-data'
        },
        timeout: 30000
      });

      setPredictions(response.data);
    } catch (err) {
      if (err.response?.status === 503) {
        setError('Model not loaded. Please train the model first using the backend.');
      } else if (err.response?.data?.detail) {
        setError(err.response.data.detail);
      } else if (err.code === 'ECONNREFUSED') {
        setError('Cannot connect to backend. Is the server running on http://localhost:8000?');
      } else {
        setError(err.message || 'Error making prediction');
      }
    } finally {
      setLoading(false);
    }
  };

  const handleClear = () => {
    setSelectedFile(null);
    setPreview(null);
    setPredictions(null);
    setError(null);
  };

  return (
    <div className="App">
      <header className="header">
        <h1>🐄 Cattle & Buffalo Breed Identifier</h1>
        <p>AI-powered breed identification system</p>
      </header>

      <main className="container">
        <div className="upload-section">
          <div className="upload-box">
            <label htmlFor="file-input" className="file-label">
              <span className="upload-icon">📸</span>
              <span className="upload-text">Click to upload or drag an image</span>
              <span className="upload-hint">
                Supported formats: JPG, PNG, BMP (Max. 50MB)
              </span>
            </label>
            <input
              id="file-input"
              type="file"
              accept="image/*"
              onChange={handleFileSelect}
              className="file-input"
            />
          </div>

          {preview && (
            <div className="preview-section">
              <h3>Image Preview</h3>
              <img src={preview} alt="Preview" className="preview-image" />
            </div>
          )}

          <div className="button-group">
            <button
              onClick={handlePredict}
              disabled={!selectedFile || loading}
              className="btn btn-primary"
            >
              {loading ? 'Analyzing...' : 'Identify Breed'}
            </button>
            <button
              onClick={handleClear}
              className="btn btn-secondary"
            >
              Clear
            </button>
          </div>
        </div>

        {error && (
          <div className="error-message">
            <span className="error-icon">❌</span>
            <span>{error}</span>
          </div>
        )}

        {predictions && (
          <div className="results-section">
            <h2>Predictions</h2>

            <div className="top-prediction">
              <h3>🏆 Top Match</h3>
              <div className="prediction-card primary">
                <div className="breed-name">{predictions.top_match}</div>
                <div className="confidence-bar">
                  <div
                    className="confidence-fill"
                    style={{ width: `${predictions.confidence}%` }}
                  ></div>
                </div>
                <div className="confidence-text">
                  Confidence: {predictions.confidence}%
                </div>
                {predictions.predictions[0] && (
                  <div className="breed-details">
                    <p><strong>Type:</strong> {predictions.predictions[0].type}</p>
                    <p><strong>Origin:</strong> {predictions.predictions[0].origin}</p>
                  </div>
                )}
              </div>
            </div>

            <div className="all-predictions">
              <h3>📊 Top 3 Predictions</h3>
              <div className="prediction-list">
                {predictions.predictions.map((pred, index) => (
                  <div key={index} className="prediction-card">
                    <div className="rank">#{index + 1}</div>
                    <div className="pred-content">
                      <div className="pred-breed">{pred.breed}</div>
                      <div className="pred-details">
                        <span className="pred-type">{pred.type}</span>
                        <span className="pred-origin">{pred.origin}</span>
                      </div>
                    </div>
                    <div className="pred-confidence">
                      <div className="confidence-bar small">
                        <div
                          className="confidence-fill"
                          style={{ width: `${pred.confidence}%` }}
                        ></div>
                      </div>
                      <span>{pred.confidence}%</span>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <button onClick={handleClear} className="btn btn-secondary">
              Try Another Image
            </button>
          </div>
        )}

        {!predictions && !loading && !error && (
          <div className="info-section">
            <h3>ℹ️ How It Works</h3>
            <div className="info-content">
              <ol>
                <li>Upload a clear image of a cattle or buffalo</li>
                <li>Our AI model analyzes the image</li>
                <li>Get predictions with confidence scores</li>
                <li>View detailed breed information</li>
              </ol>
            </div>
          </div>
        )}
      </main>

      <footer className="footer">
        <p>
          🔬 Powered by Deep Learning (ResNet-50) | 📊 {predictions?.predictions?.length || 0} breeds supported
        </p>
      </footer>
    </div>
  );
}

export default App;
